#!/usr/bin/env python
import os
import sys
import shutil
import subprocess
import argparse
from pathlib import Path

def create_tar_gz(source_dir, output_file):
    cmd = ['tar', '-czf', output_file, '-C', source_dir, '.']
    subprocess.run(cmd, check=True)

def create_tar_bz2(source_dir, output_file):
    cmd = ['tar', '-cjf', output_file, '-C', source_dir, '.']
    subprocess.run(cmd, check=True)

def create_zip(source_dir, output_file):
    cmd = ['zip', '-r', output_file, '.']
    subprocess.run(cmd, cwd=source_dir, check=True)

def create_7z(source_dir, output_file):
    cmd = ['7z', 'a', '-y', output_file, '.']
    subprocess.run(cmd, cwd=source_dir, check=True)

def main():
    parser = argparse.ArgumentParser()
    parser.add_argument('directory', help='Directory to backup')
    parser.add_argument('format', choices=['tar.gz', 'tar.bz2', 'zip', '7z'], help='Compression format')
    parser.add_argument('-o', '--output', help='Output file name')
    
    args = parser.parse_args()
    
    if not os.path.exists(args.directory):
        print(f"Error: Directory {args.directory} does not exist")
        sys.exit(1)
    
    if not args.output:
        basename = os.path.basename(os.path.normpath(args.directory))
        args.output = f"{basename}.{args.format}"
    
    try:
        if args.format == 'tar.gz':
            create_tar_gz(args.directory, args.output)
        elif args.format == 'tar.bz2':
            create_tar_bz2(args.directory, args.output)
        elif args.format == 'zip':
            create_zip(args.directory, args.output)
        elif args.format == '7z':
            create_7z(args.directory, args.output)
        print(f"Backup created successfully: {args.output}")
    except subprocess.CalledProcessError as e:
        print(f"Error creating backup: {e}")
        sys.exit(1)
    except Exception as e:
        print(f"Unexpected error: {e}")
        sys.exit(1)

if __name__ == '__main__':
    main()